package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

public class CSVFormatTest {

    @Test
    public void testWithQuote_validQuoteChar_shouldReturnNewCSVFormat() {
        // Given
        char delimiter = ',';
        Character quoteChar = '"';
        QuoteMode quoteMode = null;
        Character commentMarker = null;
        Character escapeCharacter = null;
        boolean ignoreSurroundingSpaces = false;
        boolean ignoreEmptyLines = true;
        String recordSeparator = "\r\n";
        String nullString = null;
        Object[] headerComments = null;
        String[] header = null;
        boolean skipHeaderRecord = false;
        boolean allowMissingColumnNames = false;
        boolean ignoreHeaderCase = false;
        boolean trim = false;
        boolean trailingDelimiter = false;

        CSVFormat csvFormat = createCSVFormatInstance(delimiter, quoteChar, quoteMode, commentMarker, escapeCharacter,
                ignoreSurroundingSpaces, ignoreEmptyLines, recordSeparator, nullString, headerComments, header,
                skipHeaderRecord, allowMissingColumnNames, ignoreHeaderCase, trim, trailingDelimiter);

        // When
        CSVFormat newCsvFormat = csvFormat.withQuote('"');

        // Then
        assertNotNull(newCsvFormat);
        assertEquals('"', newCsvFormat.getQuoteCharacter());
    }

    @Test
    public void testWithQuote_invalidQuoteChar_shouldThrowException() {
        // Given
        char delimiter = ',';
        Character quoteChar = '\n'; // Line break character

        CSVFormat csvFormat = createCSVFormatInstance(delimiter, quoteChar, null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When / Then
        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat.withQuote('\n');
        });
    }

    private CSVFormat createCSVFormatInstance(char delimiter, Character quoteChar, QuoteMode quoteMode,
                                              Character commentMarker, Character escapeCharacter, boolean ignoreSurroundingSpaces,
                                              boolean ignoreEmptyLines, String recordSeparator, String nullString,
                                              Object[] headerComments, String[] header, boolean skipHeaderRecord,
                                              boolean allowMissingColumnNames, boolean ignoreHeaderCase, boolean trim,
                                              boolean trailingDelimiter) {
        try {
            Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                    Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class,
                    String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
            constructor.setAccessible(true);
            return constructor.newInstance(delimiter, quoteChar, quoteMode, commentMarker, escapeCharacter,
                    ignoreSurroundingSpaces, ignoreEmptyLines, recordSeparator, nullString, headerComments, header,
                    skipHeaderRecord, allowMissingColumnNames, ignoreHeaderCase, trim, trailingDelimiter);
        } catch (NoSuchMethodException | InstantiationException | IllegalAccessException | InvocationTargetException e) {
            e.printStackTrace();
            return null;
        }
    }
}
